  ('diplomatic-d3cf880d-moex-00064', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '目前美國沒有參與下列那一個國際協議或倡議？', '["全球海洋支點（GlobalMaritimeFulcrum）", "澳英美三方安全夥伴", "印太經濟架構（IPEF）", "四方安全對話（QUAD）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00065', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '2025年3月2日「確保我們未來倫敦峰會」為烏克蘭的未來，歸結「四點計畫」。關於「四點計 畫」，下列敘述何者錯誤？', '["持續向烏克蘭提供軍事援助，並透過制裁及其他手段進一步加強對俄羅斯的經濟壓力", "確保任何和平協議都必須維護烏克蘭的主權與安全，並且烏克蘭需參與所有相關談判", "在達成和平協議後，強化烏克蘭的軍事防禦能力，以防範未來潛在的侵略行動", "派遣北約維和部隊至烏克蘭，負責確保和平協議的執行，並在戰後持續保障烏克蘭的安全"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00066', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '關於1947年「杜魯門主義」，下列敘述何者錯誤？', '["杜魯門主義成為第二次世界大戰後美國的外交政策主軸", "主張美國應該要領導各民主國家，抵抗蘇聯的共產勢力滲透，大力援助歐洲地區的經濟、軍事發展", "要求國會撥款援助義大利和希臘政府，防止當地落入共產黨手中", "杜魯門主義成為美國在世界各地援助反共政權的先例，並建立圍堵蘇聯的軍事聯盟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00067', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '下列敘述何者不屬於國際關係現實主義學派對新自由制度論（Neo-liberalInstitutionalism）的典型 批評？', '["國際制度不具獨立作用，它們只是反映強權與利益分配的結果", "在無政府狀態下，即便國際制度有監督與互惠機制，但是執行這些制度的力量過於薄弱，限制了國 家間的合作程度", "新自由制度論忽略「相對利益」（relativegains）問題，國家仍可能因為發現他國獲得較大利益而拒絕 合作", "新自由制度論將國際問題過度簡化為市場資訊與效率問題，忽視國際體系各種不平等的結構性壓迫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00068', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '關於「全球合作暨訓練架構」（GlobalCooperationandTrainingFramework,GCTF），下列敘述何者 錯誤？', '["臺灣與美國在2015年簽署備忘錄成立「全球合作暨訓練架構」，以拓展臺灣的國際空間", "GCTF已針對公共衛生、執法合作、婦女賦權、資訊安全、人道援助及災害防救等議題舉辦國 際研習營", "除美國外，日本、澳洲與加拿大也是GCTF的正式夥伴國（FullPartners）", "GCTF的主要目的是與理念相近的民主國家共同遏制威權主義在全球的擴張"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00069', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '關於「銳實力」的內容，下列敘述何者錯誤？', '["銳實力利用民主社會的開放性，散播假訊息與政治宣傳", "銳實力涉及強制手段，使用武力攻擊與侵略、經濟誘因與制裁，迫使他國就範", "銳實力侵蝕對民主機制的信任、限制自由言論與扭曲公共意見", "銳實力著眼於政治菁英、媒體工作者、學者與其他意見領袖，以獲取支持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00070', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '下列那個國家同時參與這三個多邊機制：AUKUS、QUAD和FiveEyes？', '["印度", "日本", "加拿大", "澳洲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00071', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '日本政府在 2023 年提出為了推動「自由開放的印度太平洋」願景（Free and Open Indo-Pacific, FOIP）的新計畫，其主要內容不包含下列那個項目？', '["建立一個維護和平、確立「自由」、「透明」及「法治」原則，且弱者不會因武力壓迫而屈服的 印太環境", "擴展國際合作，提升印太各國在面對氣候變遷、公共衛生、防災及災害應變與網路安全等各種 挑戰的韌性與永續性", "建立保障印太區域集體安全的軍事協調機制，強化各國軍事體系相互協作的能力", "擴展安全範圍，從海洋延伸至空域，確保整體印太公共區域之安全與穩定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00072', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '1856年克里米亞戰爭結束，列強召開巴黎和會，關於戰後的和平，下列敘述何者錯誤？', '["多瑙河航行自由化", "黑海中立化、軍艦不得隨意進出兩海峽", "同意讓土耳其成為歐洲社會的一員", "敵船上的中立國貨物得予以沒入並充公"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00073', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-7f4830a9', 'sub-diplomatic-d3cf880d-04', NULL, 'single_choice', '1899年9月美國國務卿海約翰（JohnHay）對美國駐英、德、日、俄等國大使發出訓令，命各大 使向駐在國爭取支持對華門戶開放政策，那個國家回應得最冷淡？', '["俄國", "英國", "日本", "德國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
